/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    // 1. Concatenate chunks to form s
    const s = chunks.join('');

    // 2. Tokenize s into words based on definition
    // A word consists of lowercase letters and allowed hyphens.
    // Separators are anything else (including spaces, other punctuation, etc.).
    // The definition implies that a word must be maximal: "it is not a part of a longer word".

    /**
     * Custom word extraction logic:
     * We iterate through s and identify maximal contiguous sequences of valid word characters.
     * Valid word characters: lowercase letters ('a'-'z') and hyphens ('-').
     * A hyphen is only valid if surrounded by letters.
     *
     * Since the problem states: "Any character that is not a lowercase letter or a legal hyphen
     * will act as a separator," we can first split by non-word characters.
     */

    // Regex to find contiguous sequences of characters that are either [a-z] or '-'
    // Then we need to validate if the '-' are legal within that sequence.

    // Let's use a simpler approach based on the structure of the required words.
    // A word is a maximal sequence of letters and hyphens, where hyphens are properly placed.

    const wordsMap = new Map();

    // Helper function to check if a character is a lowercase letter
    const isLetter = (char) => char >= 'a' && char <= 'z';

    // Iterate through the string to find maximal "potential" tokens (sequences of letters and hyphens)
    let i = 0;
    while (i < s.length) {
        if (!isLetter(s[i]) && s[i] !== '-') {
            i++;
            continue; // Skip separators
        }

        let start = i;
        // Find the end of the contiguous segment containing letters and hyphens
        while (i < s.length && (isLetter(s[i]) || s[i] === '-')) {
            i++;
        }
        let end = i;
        let token = s.substring(start, end);

        // Now, validate if this token constitutes a valid word according to the rules:
        // 1. Must be composed of letters and allowed hyphens. (Already handled by tokenization)
        // 2. Hyphens must be surrounded by letters.

        let isValidWord = true;
        if (token.length > 0) {
            for (let j = 1; j < token.length - 1; j++) {
                if (token[j] === '-') {
                    if (!isLetter(token[j - 1]) || !isLetter(token[j + 1])) {
                        isValidWord = false;
                        break;
                    }
                }
            }
            // Check boundaries for hyphens (though the maximal tokenization usually handles this if we assume external context is separators)
            // If token starts or ends with '-', it's invalid by rule 2 implicitly, as it's not surrounded by letters.
            if (token.length > 0 && (token[0] === '-' || token[token.length - 1] === '-')) {
                 isValidWord = false;
            }
        }

        if (isValidWord && token.length > 0) {
            // Since we extracted maximal contiguous sequences satisfying the structure, this is a word.

            // Count the occurrences of this exact word
            wordsMap.set(token, (wordsMap.get(token) || 0) + 1);
        }
    }

    // 3. Calculate results for queries
    const ans = [];
    for (const query of queries) {
        // The problem guarantees that queries[i] is a valid word.
        ans.push(wordsMap.get(query) || 0);
    }

    return ans;
}

