      // Skip separators (anything not a letter or a hyphen)
      if (!isLetter(currentChar) && currentChar != '-') {
        i += 1
        continue
      }

      val start = i
      // Find the end of the contiguous segment containing letters and hyphens
      while (i < s.length && (isLetter(s.charAt(i)) || s.charAt(i) == '-')) {
        i += 1
      }
      val end = i
      val token = s.substring(start, end)

