     * will act as a separator," we can first split by non-word characters.
     */

    // Regex to find contiguous sequences of characters that are either [a-z] or '-'
    // Then we need to validate if the '-' are legal within that sequence.

    // Let's use a simpler approach based on the structure of the required words.
    // A word is a maximal sequence of letters and hyphens, where hyphens are properly placed.

    const wordsMap = new Map();

    // Helper function to check if a character is a lowercase letter
    const isLetter = (char) => char >= 'a' && char <= 'z';

    // Iterate through the string to find maximal "potential" tokens (sequences of letters and hyphens)
